<?php
namespace Tests\Feature\Hr; use Illuminate\Support\Facades\Artisan; use Illuminate\Support\Facades\Schema; use Tests\TestCase;
class HrPhase4APerformanceRollbackTest extends TestCase { use RefreshHrDatabase; public function test_performance_tables_exist():void{$this->assertTrue(Schema::hasColumns('hr_performance_cycles',['starts_on','evaluation_starts_on','status']));$this->assertTrue(Schema::hasColumns('hr_performance_evaluations',['reviewer_type','answers','overall_score','calibrated_score']));$this->assertTrue(Schema::hasColumns('hr_performance_goals',['type','target_value','current_value','weight']));$this->assertTrue(Schema::hasTable('hr_employee_competencies'));}public function test_rollback_preserves_phase3_integrations():void{Artisan::call('migrate:rollback',['--step' => 4]);Artisan::call('migrate:rollback', ['--step' => 1]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>4]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>3]);Artisan::call('migrate:rollback',['--step'=>5]);Artisan::call('migrate:rollback',['--step'=>6]);$this->assertFalse(Schema::hasTable('hr_performance_cycles'));$this->assertTrue(Schema::hasTable('hr_integration_outbox'));$this->assertTrue(Schema::hasTable('hr_assets'));} }
